const body = $json.body ?? $json;
const labels = body.labels ?? {};
const now = new Date().toISOString();

const service = body.service ?? labels.service ?? labels.app ?? 'unknown-service';
const environment = body.environment ?? labels.environment ?? labels.env ?? 'unknown-env';
const severity = (body.severity ?? labels.severity ?? body.priority ?? 'warning').toLowerCase();

const alert = {
  incidentId: body.incidentId ?? body.alertId ?? body.fingerprint ?? `inc-${Date.now()}`,
  receivedAt: now,
  source: body.source ?? 'webhook',
  title: body.title ?? body.alertname ?? labels.alertname ?? 'Production alert received',
  service,
  environment,
  severity,
  status: body.status ?? 'firing',
  description: body.description ?? body.message ?? body.annotations?.description ?? '',
  runbookUrl: body.runbookUrl ?? body.annotations?.runbook_url ?? '',
  raw: body
};

return [{ json: alert }];

const alert = $json;

// Demo enrichment so the workflow works without Prometheus, Grafana, Loki, or Datadog.
// Replace this Code node with HTTP Request nodes when you connect real systems.
const serviceCatalog = {
  "payment-service": {
    owner: "payments-platform",
    tier: "tier-1",
    rollbackEndpoint: "https://example.com/rollback/payment-service",
    retryEndpoint: "https://example.com/retry/payment-service"
  },
  "booking-transformer": {
    owner: "platform-modernization",
    tier: "tier-1",
    rollbackEndpoint: "https://example.com/rollback/booking-transformer",
    retryEndpoint: "https://example.com/retry/booking-transformer"
  }
};

const catalog = serviceCatalog[alert.service] ?? {
  owner: "unknown-owner",
  tier: "tier-2",
  rollbackEndpoint: "https://example.com/rollback/replace-me",
  retryEndpoint: "https://example.com/retry/replace-me"
};

const metrics = {
  p95LatencyMs: alert.raw?.metrics?.p95LatencyMs ?? 1850,
  p99LatencyMs: alert.raw?.metrics?.p99LatencyMs ?? 3100,
  errorRatePercent: alert.raw?.metrics?.errorRatePercent ?? 8.4,
  throughputRps: alert.raw?.metrics?.throughputRps ?? 420,
  saturationPercent: alert.raw?.metrics?.saturationPercent ?? 86
};

const recentLogs = alert.raw?.logs ?? [
  "ERROR timeout calling downstream inventory-api after 2000ms",
  "WARN retry attempt=3 correlationId=demo-123",
  "ERROR circuit breaker open for dependency=inventory-api"
];

const runbooks = [
  {
    title: "High API latency runbook",
    content: "Check downstream dependency latency, recent deployments, circuit breaker state, saturation, and retry storms. Prefer rollback if error rate increased immediately after deployment."
  },
  {
    title: "Kafka consumer lag runbook",
    content: "Check consumer lag, partition skew, poison messages, DLQ count, and downstream write latency. Prefer retry only when idempotency key exists."
  },
  {
    title: "Safe rollback policy",
    content: "Rollback requires human approval for tier-1 services. Never execute rollback directly from AI output. The AI may recommend rollback, but an engineer must approve."
  }
];

return [{
  json: {
    ...alert,
    owner: catalog.owner,
    tier: catalog.tier,
    rollbackEndpoint: catalog.rollbackEndpoint,
    retryEndpoint: catalog.retryEndpoint,
    metrics,
    recentLogs,
    runbooks
  }
}];

