// The HTTP Request node returns the OpenAI response. Keep a defensive fallback
// so the demo continues even if the API key is not configured.
let triage;
try {
  const content = $json.choices?.[0]?.message?.content;
  triage = JSON.parse(content);
} catch (e) {
  triage = {
    severity: "medium",
    businessImpact: "Unable to call AI model. Manual triage required.",
    probableRootCause: "AI response unavailable or invalid.",
    recommendedAction: "investigate",
    confidence: 0.3,
    reasoningSummary: ["OpenAI call failed or response was not parseable."],
    customerMessage: "An alert was received and requires manual review.",
    engineerNextSteps: ["Check n8n execution logs.", "Verify OPENAI_API_KEY.", "Review alert payload manually."],
    jiraSummary: "Production alert requires manual triage",
    jiraDescription: "The AI triage step failed or returned invalid JSON."
  };
}

const original = $('Build AI Triage Prompt').first().json;
const needsApproval = ["critical", "high"].includes(triage.severity) || ["rollback", "retry"].includes(triage.recommendedAction);

const approvalBaseUrl = original.raw?.approvalBaseUrl ?? "https://YOUR_N8N_DOMAIN/webhook/ops-copilot-approval";
const approvalLinks = {
  approveRollback: `${approvalBaseUrl}?incidentId=${encodeURIComponent(original.incidentId)}&action=approve_rollback&service=${encodeURIComponent(original.service)}`,
  approveRetry: `${approvalBaseUrl}?incidentId=${encodeURIComponent(original.incidentId)}&action=approve_retry&service=${encodeURIComponent(original.service)}`,
  reject: `${approvalBaseUrl}?incidentId=${encodeURIComponent(original.incidentId)}&action=reject&service=${encodeURIComponent(original.service)}`
};

return [{
  json: {
    ...original,
    triage,
    needsApproval,
    approvalLinks,
    createdAt: new Date().toISOString()
  }
}];

const x = $json;
const safe = (value, fallback = "N/A") => value ?? fallback;

const formatList = (items = []) => {
  if (!Array.isArray(items) || items.length === 0) {
    return "• No next steps provided.";
  }

  return items.map((step) => `• ${step}`).join("\n");
};

const approvalSection = x.needsApproval
  ? [
      `*Approval Required:*`,
      `• <${x.approvalLinks.approveRollback}|Approve rollback>`,
      `• <${x.approvalLinks.approveRetry}|Approve retry>`,
      `• <${x.approvalLinks.reject}|Reject recommendation>`
    ].join("\n")
  : `*Approval:* No approval required.`;

const slackText = [
  `🚨 *AI Production Operations Copilot*`,
  ``,
  `*Incident Summary*`,
  `• *Incident ID:* \`${safe(x.incidentId)}\``,
  `• *Service:* \`${safe(x.service)}\``,
  `• *Environment:* \`${safe(x.environment)}\``,
  `• *Severity:* *${safe(x.triage?.severity).toUpperCase()}*`,
  `• *Confidence:* ${safe(x.triage?.confidence)}`,
  ``,
  `*Impact*`,
  `${safe(x.triage?.businessImpact)}`,
  ``,
  `*Likely Root Cause*`,
  `${safe(x.triage?.probableRootCause)}`,
  ``,
  `*Recommended Action*`,
  `${safe(x.triage?.recommendedAction)}`,
  ``,
  `*Engineer Next Steps*`,
  formatList(x.triage?.engineerNextSteps),
  ``,
  approvalSection
].join("\n");

const jiraText = [
  `${safe(x.triage?.jiraDescription)}`,
  ``,
  `*Incident Summary*`,
  `• *Incident ID:* \`${safe(x.incidentId)}\``,
  `• *Service:* \`${safe(x.service)}\``,
  `• *Environment:* \`${safe(x.environment)}\``,
  `• *Severity:* *${safe(x.triage?.severity).toUpperCase()}*`,
  `• *Confidence:* ${safe(x.triage?.confidence)}`,
  ``,
  `*Impact*`,
  `${safe(x.triage?.businessImpact)}`,
  ``,
  `*Likely Root Cause*`,
  `${safe(x.triage?.probableRootCause)}`,
  ``,
  `*Recommended Action*`,
  `${safe(x.triage?.recommendedAction)}`,
  ``,
  `*Engineer Next Steps*`,
  formatList(x.triage?.engineerNextSteps)
].join("\n");

const jiraPayload = {
  fields: {
    project: { key: $vars.JIRA_PROJECT_KEY || "OPS" },
    summary: x.triage.jiraSummary || `[${x.triage.severity}] ${x.title}`,
    description: {
      type: "doc",
      version: 1,
      content: [
        {
          type: "paragraph",
          content: [{ type: "text", text: jiraText }]
        }
      ]
    },
    issuetype: { name: "Task" }
  }
};

const learningRecord = {
  incidentId: x.incidentId,
  service: x.service,
  environment: x.environment,
  severity: x.triage.severity,
  recommendedAction: x.triage.recommendedAction,
  probableRootCause: x.triage.probableRootCause,
  confidence: x.triage.confidence,
  runbooksUsed: (x.runbooks || []).map(r => r.title),
  metrics: x.metrics,
  timestamp: new Date().toISOString()
};

return [{ json: { ...x, slackText, jiraText, jiraPayload, learningRecord } }];

const item = $json;
const learningRecord = item.learningRecord;

const pageTitle = `Incident Learning - ${item.incidentId} - ${new Date().toISOString().split('T')[0]}`;

const pageContent = {
  type: "doc",
  version: 1,
  content: [
    {
      type: "heading",
      attrs: { level: 1 },
      content: [{ type: "text", text: `Incident Learning: ${item.incidentId}` }]
    },
    {
      type: "paragraph",
      content: [{ type: "text", text: `Timestamp: ${learningRecord.timestamp}` }]
    },
    {
      type: "heading",
      attrs: { level: 2 },
      content: [{ type: "text", text: "Service Details" }]
    },
    {
      type: "bulletList",
      content: [
        {
          type: "listItem",
          content: [{
            type: "paragraph",
            content: [{ type: "text", text: `Service: ${learningRecord.service}` }]
          }]
        },
        {
          type: "listItem",
          content: [{
            type: "paragraph",
            content: [{ type: "text", text: `Environment: ${learningRecord.environment}` }]
          }]
        },
        {
          type: "listItem",
          content: [{
            type: "paragraph",
            content: [{ type: "text", text: `Severity: ${learningRecord.severity}` }]
          }]
        }
      ]
    },
    {
      type: "heading",
      attrs: { level: 2 },
      content: [{ type: "text", text: "Analysis" }]
    },
    {
      type: "bulletList",
      content: [
        {
          type: "listItem",
          content: [{
            type: "paragraph",
            content: [{ type: "text", text: `Recommended Action: ${learningRecord.recommendedAction}` }]
          }]
        },
        {
          type: "listItem",
          content: [{
            type: "paragraph",
            content: [{ type: "text", text: `Probable Root Cause: ${learningRecord.probableRootCause}` }]
          }]
        },
        {
          type: "listItem",
          content: [{
            type: "paragraph",
            content: [{ type: "text", text: `Confidence: ${learningRecord.confidence}` }]
          }]
        }
      ]
    },
    {
      type: "heading",
      attrs: { level: 2 },
      content: [{ type: "text", text: "Metrics" }]
    },
    {
      type: "codeBlock",
      attrs: { language: "json" },
      content: [{ type: "text", text: JSON.stringify(learningRecord.metrics, null, 2) }]
    },
    {
      type: "heading",
      attrs: { level: 2 },
      content: [{ type: "text", text: "Runbooks Used" }]
    },
    {
      type: "bulletList",
      content: (learningRecord.runbooksUsed || []).map(runbook => ({
        type: "listItem",
        content: [{
          type: "paragraph",
          content: [{ type: "text", text: runbook }]
        }]
      }))
    }
  ]
};

return [{
  json: {
    ...item,
    confluencePageTitle: pageTitle,
    confluencePageContent: pageContent
  }
}];

const body = $json.body ?? $json;
const issue = body.issue ?? {};
const fields = issue.fields ?? {};
const status = fields.status?.name ?? '';

const isDoneOrDeployed = ['Done', 'Deployed'].includes(status);

if (!isDoneOrDeployed) {
  return [];
}

const descriptionText = fields.description ?? '';

return [{
  json: {
    issueKey: issue.key,
    status: status,
    summary: fields.summary ?? '',
    description: descriptionText,
    project: fields.project?.key ?? '',
    timestamp: new Date().toISOString()
  }
}];

const items = $input.all();

const agentItem = items.find(item => item.json.output !== undefined);
const originalDataItem = items.find(item => item.json.slackText !== undefined);

const agentOutput = agentItem?.json.output || '';
let jiraCreated = false;

try {
  const parsed = JSON.parse(agentOutput);
  const message = parsed.message || '';
  jiraCreated = message.toLowerCase().includes('created') && !message.toLowerCase().includes('duplicate');
} catch (e) {
  jiraCreated = agentOutput.toLowerCase().includes('created') && !agentOutput.toLowerCase().includes('duplicate');
}

const originalData = originalDataItem?.json || {};

return [{
  json: {
    ...originalData,
    agentOutput,
    jiraCreated
  }
}];
